solution: ```class Solution {
public:
    int rearrangeCharacters(string s, string target) {
        int cntS[26] = {0};
        int cntT[26] = {0};
        for (char c : s) cntS[c - 'a']++;
        for (char c : target) cntT[c - 'a']++;
        int ans = 100;
        for (int i = 0; i < 26; ++i) {
            if (cntT[i] == 0) continue;
            ans = min(ans, cntS[i] / cntT[i]);
        }
        return ans;
    }
};
```
